import React, { Component } from 'react'
import { Form, Tab, Tabs, Col, Row, Badge } from 'react-bootstrap';
import httpClient from 'axios';

interface SolrSettingsProps {
  dataSourceUrl: string
  dataSourceError: boolean
  setDataSourceUrl: any
  setSolrUrlPart: any
  solrBaseUrl: string
  solrCore: string
  solrQuery: string
  accessChild: any
}

/* interface SolrSettingsState {
  selectedSolrCore: string
  solrBaseUrl: string
  solrQuery: string
  solrInstanceStatus: boolean
  items: string[]
} */

export default class SolrSettings extends Component<SolrSettingsProps, any> {

  constructor(props) {
    super(props);

    this.state = {
      solrBaseUrl: 'http://localhost:8983/solr/',
      solrCore: 'dc_cubes', 
      solrQuery: '/query?q=*:*&start=0&rows=30000',
      solrInstanceStatus: false, // false -> offline, true -> online
      items: [],
    }
  }

  render() {
    return (
        <div>
            <h2>Solr Einstellungen</h2>
            <br/>
            <Tabs defaultActiveKey="home" transition={false} id="noanim-tab-example">
                <Tab eventKey="home" title="Einstellungen">
                    <Form>
                        <br/>
                        <Form.Group as={Row} controlId="inputSolrBaseUrl">
                          <Col sm="2">
                            URL Preview:
                          </Col>
                          <Col sm="10">
                            { 
                              <a href={this.props.solrBaseUrl.concat(this.props.solrCore, this.props.solrQuery)}>
                                {this.props.solrBaseUrl.concat(this.props.solrCore, this.props.solrQuery)}
                              </a>
                            }
                          </Col>
                        </Form.Group>

                        <Form.Group as={Row} controlId="inputSolrBaseUrl">
                          <Form.Label column sm="2">
                            Base URL:
                          </Form.Label>
                          <Col sm="8">
                            <Form.Control  onChange={this.handleChange} name="solrBaseUrl" value={this.props.solrBaseUrl} />
                          </Col>
                          <Col sm="2">
                            {
                              this.props.dataSourceError ? <Badge variant="danger">Offline</Badge>
                              : <Badge variant="success">Online</Badge>
                            }
                          </Col>
                        </Form.Group>
                    
                        <Form.Group>
                            <Form.Label>Core auswählen:</Form.Label>
                            <Form.Control onChange={this.handleChange} name="solrCore" as="select" value={this.props.solrCore}>
                            {this.state.items}
                            </Form.Control>
                        </Form.Group>

                        <Form.Group controlId="exampleForm.ControlTextarea1">
                          <Form.Label>Query:</Form.Label>
                          <Form.Control onChange={this.handleChange} as="textarea" rows="3" name="solrQuery" value={this.props.solrQuery} />
                        </Form.Group>
                  </Form>
                </Tab>
                <Tab eventKey="profile" title="Vorschau">
                </Tab>
            </Tabs>
        </div>
    )
  }

  componentDidMount() {
    console.log(1)
    const url = this.state.solrBaseUrl.concat("admin/cores?action=STATUS&indexInfo=false&wt=json")
    this.getAllSolrCores(url)
  }

  handleChange = (e) => {
    const target = e.target;
    const value = target.value;
    const name = target.name;

    if (name === "solrBaseUrl") {
      this.setState({
        [name]: value,
        items: [],
        solrInstanceStatus: false
      })

      const solrCoresUrl = value.concat("admin/cores?action=STATUS&indexInfo=false&wt=json")
      this.getAllSolrCores(solrCoresUrl)
      this.props.setSolrUrlPart("solrBaseUrl", value)
    }

    if (name === "solrQuery") {
      this.setState({
        [name]: value
      })
      this.props.setSolrUrlPart("solrQuery", value)
    }

    if (name === "solrCore") {
      this.setState({
        [name]: value
      })
      this.props.setSolrUrlPart("solrCore", value)
    }
  };

  getAllSolrCores = (url: string) => {
    httpClient.get(url)
    .then((data) => {
        const dataItems = [];
        let strCores : string[] = Object.keys(data.data.status || {})

        strCores.forEach((strCore, index) => {
            dataItems.push(<option key={index} value={strCore}>{strCore}</option>);
        });

        this.setState({
          items: dataItems
        })
        this.props.accessChild('dataSourceError', false)
    })
    .catch((error) => {
        console.log(error)
    }); 
  }
}  